import React, { useRef, useEffect } from "react";


const KNIGHT_IMG_B64 = "";

const PALM_IMG_B64 = "";

function drawStars(ctx, W, H) {
  const starCount = 120;
  ctx.save();
  ctx.fillStyle = "white";
  for (let i = 0; i < starCount; i++) {
    const x = Math.random() * W;
    const y = Math.random() * H * 0.5;
    const r = Math.random() * 1.2;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.restore();
}

function drawSkyGradient(ctx, W, H) {
  const grad = ctx.createLinearGradient(0, 0, 0, H);
  grad.addColorStop(0, "#150b2e");
  grad.addColorStop(0.3, "#351c61");
  grad.addColorStop(0.65, "#7a3fa3");
  grad.addColorStop(1, "#e48dbd");
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, W, H);
}

function drawAurora(ctx, W, H, t) {
  const colors = [
    "rgba(116,255,200,0.5)",
    "rgba(120,180,255,0.45)",
    "rgba(200,120,255,0.4)",
    "rgba(255,150,220,0.4)",
  ];

  ctx.globalCompositeOperation = "lighter"; // campur warna aurora lebih efisien

  for (let i = 0; i < colors.length; i++) {
    ctx.save();
    ctx.beginPath();

    const baseY = H * 0.3 - i * 25;

    ctx.moveTo(0, baseY + 100);

    for (let x = 0; x <= W; x += 80) {
      const slope = (x / W) * 80;
      const y =
        baseY -
        slope -
        Math.sin(x / 140 + t * 0.6 + i) * 25 -
        Math.cos(x / 80 - t * 0.3 + i) * 10;
      ctx.lineTo(x, y);
    }

    for (let x = W; x >= 0; x -= 8) {
      const slope = (x / W) * 80;
      const y =
        baseY -
        slope +
        50 -
        Math.sin(x / 140 + t * 0.6 + i) * 25 -
        Math.cos(x / 80 - t * 0.3 + i) * 10;
      ctx.lineTo(x, y);
    }

    ctx.closePath();

    const grad = ctx.createLinearGradient(0, baseY, 0, baseY + 100);
    grad.addColorStop(0, colors[i]);
    grad.addColorStop(0.5, "rgba(255,255,255,0.05)");
    grad.addColorStop(1, "transparent");

    ctx.fillStyle = grad;
    ctx.filter = `blur(${8 + i * 2}px)`; // blur lebih ringan
    ctx.globalAlpha = 0.9 - i * 0.15;
    ctx.fill();
    ctx.restore();
  }

  ctx.globalCompositeOperation = "source-over";
}

function mountainRidge(seed, W, H, octaves = 6) {
  const pts = [];
  const steps = W + 1;
  for (let i = 0; i <= steps; i++) {
    const x = (i / steps) * W;
    const nx = x / W;
    let y = 0;
    for (let o = 0; o < octaves; o++) {
      const f = Math.pow(2, o);
      const a = Math.pow(0.5, o);
      y += a * Math.sin(nx * f * Math.PI * (2 + seed * 0.7) + seed * 3.1 + o * 1.3);
    }
    const peakCenter = 0.28 - seed * 0.04;
    // Puncak utama lebih tinggi dengan lereng lebih lebar agar tetap realistis
    const mainPeak = -0.88 * Math.exp(-Math.pow((nx - peakCenter) * 3.8, 2));
    // Puncak kecil di sisi kanan untuk variasi natural
    const secondPeak = -0.32 * Math.exp(-Math.pow((nx - (peakCenter + 0.18)) * 6.0, 2));
    y = y * 0.14 + mainPeak + secondPeak;
    pts.push({ x, y: H * (0.52 + seed * 0.06 + y * 0.32) });
  }
  return pts;
}

function drawMountains(ctx, W, H) {
  const ridges = [
    { pts: mountainRidge(0.0, W, H), fill: ["#0d0820", "#1a0d38"] },
    { pts: mountainRidge(0.5, W, H), fill: ["#0a0618", "#120825"] },
    { pts: mountainRidge(1.0, W, H), fill: ["#060412", "#0d0520"] },
  ];
  ridges.forEach(({ pts, fill }) => {
    const grad = ctx.createLinearGradient(0, 0, 0, H);
    grad.addColorStop(0, fill[0]);
    grad.addColorStop(1, fill[1]);
    ctx.beginPath();
    ctx.moveTo(0, H);
    pts.forEach(({ x, y }) => ctx.lineTo(x, y));
    ctx.lineTo(W, H);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();
  });
  return ridges;
}

const palmImg = new Image();
palmImg.src = `data:image/webp;base64,${PALM_IMG_B64}`;

const PALM_GROVE = [
  { xRatio: 0.80, heightRatio: 0.27, flipX: true  },
  { xRatio: 0.88, heightRatio: 0.32, flipX: false },
  { xRatio: 0.96, heightRatio: 0.28, flipX: true  },
];

const knightImg = new Image();
knightImg.src = `data:image/png;base64,${KNIGHT_IMG_B64}`;

// Hitung sekali saja: rasio transparent padding di bawah gambar knight
// (0 = tidak ada padding, 0.1 = 10% dari bawah adalah transparan)
let knightBottomRatio = 0;
knightImg.onload = () => {
  const nw = knightImg.naturalWidth;
  const nh = knightImg.naturalHeight;
  const tc = document.createElement("canvas");
  tc.width = nw; tc.height = nh;
  const tctx = tc.getContext("2d");
  tctx.drawImage(knightImg, 0, 0);
  const d = tctx.getImageData(0, 0, nw, nh).data;
  let lowestRow = 0;
  for (let row = nh - 1; row >= 0; row--) {
    let found = false;
    for (let col = 0; col < nw; col++) {
      if (d[(row * nw + col) * 4 + 3] > 20) { found = true; break; }
    }
    if (found) { lowestRow = row; break; }
  }
  // rasio dari bawah gambar ke pixel paling bawah yang ada isinya
  knightBottomRatio = (nh - 1 - lowestRow) / nh;
};


function drawPalms(ctx, W, H, ridges) {
  if (!palmImg.complete) return;
  const frontPts = ridges[2]?.pts ?? [];
  const getRidgeY = (xRatio) => {
    if (!frontPts.length) return H * 0.58;
    const xi = Math.round(xRatio * (frontPts.length - 1));
    return frontPts[Math.min(xi, frontPts.length - 1)]?.y ?? H * 0.58;
  };
  PALM_GROVE.forEach(({ xRatio, heightRatio, flipX }) => {
    const cx = xRatio * W;
    const ph = H * heightRatio;
    const baseY = getRidgeY(xRatio) + 6;
    const drawH = ph;
    const drawW = ph;
    const drawX = cx - drawW / 2;
    const drawY = baseY - drawH * 0.88;
    ctx.save();
    if (flipX) { ctx.translate(cx * 2, 0); ctx.scale(-1, 1); }
    ctx.globalCompositeOperation = "multiply";
    ctx.drawImage(palmImg, drawX, drawY, drawW, drawH);
    ctx.restore();
  });
}


function drawCrescentMoon(ctx, W, H) {
  const cx = W * 0.78;
  const cy = H * 0.10;
  const r = Math.min(W, H) * 0.034;

  ctx.save();

  // Outer glow halo
  const halo = ctx.createRadialGradient(cx, cy, r * 0.8, cx, cy, r * 3.2);
  halo.addColorStop(0, "rgba(255,240,180,0.18)");
  halo.addColorStop(1, "rgba(255,240,180,0)");
  ctx.fillStyle = halo;
  ctx.beginPath();
  ctx.arc(cx, cy, r * 3.2, 0, Math.PI * 2);
  ctx.fill();

  // Moon body (full disc)
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = "rgba(255,248,200,0.92)";
  ctx.fill();

  // Crescent shadow — offset circle to carve the crescent shape
  ctx.beginPath();
  ctx.arc(cx + r * 0.55, cy - r * 0.08, r * 0.82, 0, Math.PI * 2);
  ctx.fillStyle = "#150b2e"; // same as sky top color
  ctx.fill();

  ctx.restore();
}

function drawSilhouettes(ctx, W, H, ridges) {
  if (!knightImg.complete || knightImg.naturalWidth === 0) return;

  const frontPts = ridges[0]?.pts ?? [];

  // Cari titik terendah (puncak gunung) di sekitar xRatio 0.20–0.36
  let peakY = H;
  let peakX = 0.282 * W;
  for (let r = 0.20; r <= 0.36; r += 0.001) {
    const xi = Math.round(r * (frontPts.length - 1));
    const y = frontPts[Math.min(xi, frontPts.length - 1)]?.y ?? H;
    if (y < peakY) {
      peakY = y;
      peakX = r * W;
    }
  }

  const mountainHeight = H - peakY;
  const imgH = mountainHeight * 0.22;
  const imgW = imgH * (knightImg.naturalWidth / knightImg.naturalHeight);

  // Geser gambar ke bawah sebesar transparent padding di bawah gambar + sedikit ekstra
  // sehingga kaki kuda yang terlihat tepat menyentuh puncak gunung
  const drawX = peakX - imgW * 0.45;
  const drawY = peakY - imgH + (knightBottomRatio * imgH) + imgH * 0.12;

  ctx.save();
  ctx.drawImage(knightImg, drawX, drawY, imgW, imgH);
  ctx.restore();
}

function drawValleyMist(ctx, W, H, ridges, t) {
  // Mist sits in the valley between mountains — around x 0.45–0.75, slightly below ridge line
  const refPts = ridges[1]?.pts ?? [];
  const getY = (xRatio) => {
    if (!refPts.length) return H * 0.55;
    const xi = Math.round(xRatio * (refPts.length - 1));
    return refPts[Math.min(xi, refPts.length - 1)]?.y ?? H * 0.55;
  };

  ctx.save();

  // Draw 3 overlapping mist layers with slow drift
  for (let layer = 0; layer < 3; layer++) {
    const drift = Math.sin(t * 0.12 + layer * 1.1) * W * 0.015;
    const mistY = getY(0.58) + layer * H * 0.012;
    const mistH = H * 0.045 + layer * H * 0.02;

    const grad = ctx.createLinearGradient(0, mistY - mistH * 0.5, 0, mistY + mistH);
    grad.addColorStop(0, "rgba(180,140,220,0)");
    grad.addColorStop(0.3, `rgba(180,140,220,${0.13 - layer * 0.03})`);
    grad.addColorStop(0.7, `rgba(160,120,200,${0.10 - layer * 0.025})`);
    grad.addColorStop(1, "rgba(140,100,180,0)");

    ctx.beginPath();
    // Wavy top edge of mist
    ctx.moveTo(W * 0.30 + drift, mistY);
    for (let x = W * 0.30; x <= W * 0.82; x += 18) {
      const nx = (x - W * 0.30) / (W * 0.52);
      const wy = mistY + Math.sin(nx * Math.PI * 3 + t * 0.25 + layer) * H * 0.008;
      ctx.lineTo(x + drift, wy);
    }
    ctx.lineTo(W * 0.82 + drift, mistY + mistH);
    ctx.lineTo(W * 0.30 + drift, mistY + mistH);
    ctx.closePath();

    ctx.filter = `blur(${10 + layer * 6}px)`;
    ctx.fillStyle = grad;
    ctx.fill();
  }

  ctx.filter = "none";
  ctx.restore();
}

function drawLake(ctx, W, H, t, sceneImage, starCanvas) {
  const lakeTopBase = H * 0.655;

  const waveAmplitude = 6;
  const waveLength = 300;
  const lakeTop = (x) =>
    lakeTopBase + Math.sin(x / waveLength + t * 0.8) * waveAmplitude;

  const grad = ctx.createLinearGradient(0, lakeTopBase, 0, H);
  grad.addColorStop(0, "#1c0e30");
  grad.addColorStop(0.5, "#0b0520");
  grad.addColorStop(1, "#04010a");
  ctx.fillStyle = grad;

  ctx.beginPath();
  ctx.moveTo(0, lakeTop(0));
  for (let x = 0; x <= W; x += 10) {
    ctx.lineTo(x, lakeTop(x));
  }
  ctx.lineTo(W, H);
  ctx.lineTo(0, H);
  ctx.closePath();
  ctx.fill();

  if (sceneImage) {
    ctx.save();
    ctx.beginPath();
    ctx.moveTo(0, lakeTop(0));
    for (let x = 0; x <= W; x += 10) {
      ctx.lineTo(x, lakeTop(x));
    }
    ctx.lineTo(W, H);
    ctx.lineTo(0, H);
    ctx.closePath();
    ctx.clip();

    const waveAmp = 5;
    const waveLen = 180;
    const stripWidth = 6; // lebih jarang untuk performa

    ctx.filter = "blur(4px)";
    for (let x = 0; x < W; x += stripWidth) {
      const offset = Math.sin(x / waveLen + t * 2) * waveAmp;
      ctx.save();
      ctx.translate(x, lakeTopBase * 2 + offset);
      ctx.scale(1, -1);
      ctx.globalAlpha = 0.45;
      ctx.drawImage(sceneImage, x, 0, stripWidth, H, 0, 0, stripWidth, H);

      if (starCanvas) {
        ctx.globalAlpha = 0.2;
        ctx.filter = "none";
        ctx.drawImage(
          starCanvas,
          x,
          0,
          stripWidth,
          H,
          0,
          -H * 0.2,
          stripWidth * 1.8,
          H * 1.8
        );
      }
      ctx.restore();
    }

    ctx.restore();
  }

  ctx.save();
  ctx.globalAlpha = 0.3;
  ctx.lineWidth = 1;

  for (let i = 0; i < 5; i++) {
    ctx.beginPath();
    for (let x = 0; x <= W; x += 15) {
      const y = lakeTop(x) + Math.sin(x / 80 + t * 3 + i) * 3 + i * 8;
      ctx.lineTo(x, y);
    }
    ctx.strokeStyle = `rgba(255,255,255,${0.04 - i * 0.005})`;
    ctx.stroke();
  }

  ctx.restore();
}

export default function App() {
  const canvasRef = useRef();

  useEffect(() => {
    const canvas = canvasRef.current;
    let ctx = canvas.getContext("2d");
    let dpr = window.devicePixelRatio || 1;
    let W = window.innerWidth,
      H = window.innerHeight;

    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = W + "px";
    canvas.style.height = H + "px";
    ctx.scale(dpr, dpr);

    const starCanvas = document.createElement("canvas");
    starCanvas.width = W;
    starCanvas.height = H;
    const starCtx = starCanvas.getContext("2d");
    drawStars(starCtx, W, H);

    // Buat offscreen canvas sekali saja
    const offCanvas = document.createElement("canvas");
    offCanvas.width = W;
    offCanvas.height = H;
    const offCtx = offCanvas.getContext("2d");

    function animate() {
      const t = performance.now() / 1000;

      // bersihkan frame
      offCtx.clearRect(0, 0, W, H);
      ctx.clearRect(0, 0, W, H);

      drawSkyGradient(offCtx, W, H);
      offCtx.drawImage(starCanvas, 0, 0);
      drawAurora(offCtx, W, H, t);
      const ridges = drawMountains(offCtx, W, H);
      drawPalms(offCtx, W, H, ridges);
      drawValleyMist(offCtx, W, H, ridges, t);
      drawSilhouettes(offCtx, W, H, ridges);
      drawCrescentMoon(offCtx, W, H);

      ctx.drawImage(offCanvas, 0, 0, W, H);
      drawLake(ctx, W, H, t, offCanvas, starCanvas);

      requestAnimationFrame(animate);
    }

    animate();

    function resize() {
      W = window.innerWidth;
      H = window.innerHeight;
      canvas.width = W * dpr;
      canvas.height = H * dpr;
      canvas.style.width = W + "px";
      canvas.style.height = H + "px";
      ctx = canvas.getContext("2d");
      ctx.scale(dpr, dpr);

      offCanvas.width = W;
      offCanvas.height = H;
      starCanvas.width = W;
      starCanvas.height = H;
      drawStars(starCtx, W, H);
    }

    window.addEventListener("resize", resize);
    return () => window.removeEventListener("resize", resize);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: "100vw",
        height: "100vh",
        zIndex: 1,
      }}
    />
  );
}
